/// Abstract interface for agent backends.
pub trait AgentBackend {
    /// Send a message with context and return the response.
    fn send_message(&self, message: &str, context: &[Message]) -> AgentResponse;

    /// Return the backend name.
    fn name(&self) -> &str;

    /// Whether this backend supports streaming output.
    fn supports_streaming(&self) -> bool { false }
}



/// Extract a numeric version from a gemini model name (e.g. "gemini-3-flash-preview" -> 3.0).
fn extract_gemini_version(model: &str) -> Option<f64> {
    for part in model.split('-') {
        if let Ok(v) = part.parse::<f64>() {
            return Some(v);
        }
        // Handle versions like "2.5" embedded in hyphenated segments
        if part.contains('.') {
            if let Ok(v) = part.parse::<f64>() {
                return Some(v);
            }
        }
    }
    None
}

/// Validate a gemini model meets minimum version requirements.
/// Flash models require version >= 3, Pro models require version >= 2.5.
fn validate_gemini_model(model: &str, default: &str) -> String {
    if model.contains("flash") {
        if let Some(ver) = extract_gemini_version(model) {
            if ver >= 3.0 { return model.to_string(); }
        }
        eprintln!("Warning: gemini flash requires version >= 3, using {}", default);
        return default.to_string();
    }
    if model.contains("pro") {
        if let Some(ver) = extract_gemini_version(model) {
            if ver >= 2.5 { return model.to_string(); }
        }
        eprintln!("Warning: gemini pro requires version >= 2.5, using {}", default);
        return default.to_string();
    }
    model.to_string()
}

/// CLI-based backend that shells out to a command.
pub struct CliBackend {
    pub backend_name: String,
    pub command: String,
    pub args: Vec<String>,
    pub model: Option<String>,
}

impl CliBackend {
    pub fn new(name: &str, command: &str, args: &[&str], model: Option<String>) -> Self {
        Self {
            backend_name: name.to_string(),
            command: command.to_string(),
            args: args.iter().map(|s| s.to_string()).collect(),
            model,
        }
    }
}

impl AgentBackend for CliBackend {
    fn send_message(&self, message: &str, _context: &[Message]) -> AgentResponse {
        let mut cmd = Command::new(&self.command);
        for arg in &self.args {
            cmd.arg(arg);
        }
        if let Some(ref model) = self.model {
            cmd.arg(model);
        }
        cmd.arg(message);
        // Remove CLAUDECODE env var to allow nested Claude Code invocations
        cmd.env_remove("CLAUDECODE");
        cmd.stdout(Stdio::piped()).stderr(Stdio::piped());

        match cmd.output() {
            Ok(output) => {
                let mut content = String::from_utf8_lossy(&output.stdout).to_string();
                let stderr_text = String::from_utf8_lossy(&output.stderr);
                if !stderr_text.is_empty() {
                    if content.trim().is_empty() {
                        // No stdout — surface stderr as the response (error case)
                        content = format!("stderr: {}", stderr_text);
                    } else {
                        // Both present — log stderr as diagnostic
                        eprintln!("[{}] stderr: {}", self.backend_name, stderr_text.trim());
                    }
                }
                AgentResponse {
                    content,
                    model: self.backend_name.clone(),
                    ..Default::default()
                }
            }
            Err(e) => AgentResponse {
                content: format!("Error running {}: {}", self.command, e),
                model: self.backend_name.clone(),
                ..Default::default()
            },
        }
    }

    fn name(&self) -> &str { &self.backend_name }
}


use std::io::{BufRead, Write};

/// Parse a single SSE event line.
/// Returns the data payload if the line starts with "data: ", or None.
pub fn parse_sse_line(line: &str) -> Option<String> {
    let trimmed = line.trim();
    if trimmed == "data: [DONE]" {
        return None;
    }
    if let Some(data) = trimmed.strip_prefix("data: ") {
        Some(data.to_string())
    } else {
        None
    }
}

/// Extract content delta from an SSE JSON payload.
/// Supports OpenAI/OpenRouter format (choices[0].delta.content)
/// and Anthropic format (delta.text).
pub fn extract_content_delta(json_str: &str) -> Option<String> {
    let json: serde_json::Value = serde_json::from_str(json_str).ok()?;
    // OpenAI / OpenRouter format
    if let Some(content) = json.get("choices")
        .and_then(|c| c.get(0))
        .and_then(|c| c.get("delta"))
        .and_then(|d| d.get("content"))
        .and_then(|c| c.as_str()) {
        return Some(content.to_string());
    }
    // Anthropic format
    if let Some(text) = json.get("delta")
        .and_then(|d| d.get("text"))
        .and_then(|t| t.as_str()) {
        return Some(text.to_string());
    }
    None
}

/// Extract token usage from an SSE JSON payload.
/// OpenAI: final chunk has usage.prompt_tokens / completion_tokens
/// Anthropic: message_start has usage.input_tokens, message_delta has usage.output_tokens
pub fn extract_usage_from_sse(json_str: &str) -> Option<(u64, u64)> {
    let json: serde_json::Value = serde_json::from_str(json_str).ok()?;
    // OpenAI format: usage in final chunk
    if let Some(usage) = json.get("usage") {
        let input = usage.get("prompt_tokens").and_then(|v| v.as_u64()).unwrap_or(0);
        let output = usage.get("completion_tokens").and_then(|v| v.as_u64()).unwrap_or(0);
        if input > 0 || output > 0 { return Some((input, output)); }
    }
    // Anthropic message_start: usage.input_tokens
    if json.get("type").and_then(|t| t.as_str()) == Some("message_start") {
        if let Some(usage) = json.get("message").and_then(|m| m.get("usage")) {
            let input = usage.get("input_tokens").and_then(|v| v.as_u64()).unwrap_or(0);
            return Some((input, 0));
        }
    }
    // Anthropic message_delta: usage.output_tokens
    if json.get("type").and_then(|t| t.as_str()) == Some("message_delta") {
        if let Some(usage) = json.get("usage") {
            let output = usage.get("output_tokens").and_then(|v| v.as_u64()).unwrap_or(0);
            return Some((0, output));
        }
    }
    None
}

/// Send a streaming request and print output progressively.
/// Returns the complete accumulated response content and token usage.
pub fn send_streaming(
    client: &reqwest::blocking::Client,
    endpoint: &str,
    api_key: Option<&str>,
    api_format: &str,
    body: serde_json::Value,
) -> (String, u64, u64) {
    let mut req = client.post(endpoint)
        .header("Content-Type", "application/json");
    if let Some(key) = api_key {
        if api_format == "anthropic" {
            req = req.header("x-api-key", key)
                .header("anthropic-version", "2023-06-01");
        } else {
            req = req.header("Authorization", format!("Bearer {}", key));
        }
    }

    match req.json(&body).send() {
        Ok(resp) => {
            let mut full_content = String::new();
            let mut input_tokens: u64 = 0;
            let mut output_tokens: u64 = 0;
            let reader = std::io::BufReader::new(resp);
            for line in reader.lines() {
                match line {
                    Ok(line) => {
                        if let Some(data) = parse_sse_line(&line) {
                            if let Some(delta) = extract_content_delta(&data) {
                                print!("{}", delta);
                                let _ = std::io::stdout().flush();
                                full_content.push_str(&delta);
                            }
                            // Extract usage from SSE chunks (final chunk or Anthropic events)
                            if let Some((inp, out)) = extract_usage_from_sse(&data) {
                                input_tokens += inp;
                                output_tokens += out;
                            }
                        }
                    }
                    Err(_) => break,
                }
            }
            println!();
            (full_content, input_tokens, output_tokens)
        }
        Err(e) => {
            (format!("Streaming error: {}", e), 0, 0)
        }
    }
}


/// API-based backend that sends HTTP requests.
/// Supports OpenAI and Anthropic message formats via api_format field.
pub struct ApiBackend {
    pub backend_name: String,
    pub endpoint: String,
    pub api_key: Option<String>,
    pub model: String,
    pub stream: bool,
    pub api_format: String,
}

impl ApiBackend {
    pub fn new(name: &str, endpoint: &str, api_key: Option<String>, model: &str, stream: bool, api_format: &str) -> Self {
        Self {
            backend_name: name.to_string(),
            endpoint: endpoint.to_string(),
            api_key,
            model: model.to_string(),
            stream,
            api_format: api_format.to_string(),
        }
    }

    fn build_messages(&self, message: &str, context: &[Message]) -> Vec<serde_json::Value> {
        let mut messages: Vec<serde_json::Value> = context.iter().map(|m| {
            serde_json::json!({
                "role": m.role,
                "content": m.content,
            })
        }).collect();
        messages.push(serde_json::json!({
            "role": "user",
            "content": message,
        }));
        messages
    }

    pub fn build_request_body(&self, message: &str, context: &[Message]) -> serde_json::Value {
        use crate::tools::tool_schemas_json;
        let messages = self.build_messages(message, context);
        let tools = tool_schemas_json();

        if self.api_format == "anthropic" {
            // Anthropic: system is top-level, tools use input_schema
            let anthropic_tools: Vec<serde_json::Value> = tools.iter().map(|t| {
                let func = &t["function"];
                serde_json::json!({
                    "name": func["name"],
                    "description": func["description"],
                    "input_schema": func["parameters"],
                })
            }).collect();
            let mut body = serde_json::json!({
                "model": self.model,
                "messages": messages,
                "max_tokens": 4096,
            });
            if !anthropic_tools.is_empty() {
                body["tools"] = serde_json::json!(anthropic_tools);
            }
            body
        } else {
            // OpenAI / OpenRouter / Ollama format
            let mut body = serde_json::json!({
                "model": self.model,
                "messages": messages,
            });
            if !tools.is_empty() {
                body["tools"] = serde_json::json!(tools);
            }
            body
        }
    }

    fn add_auth_header(&self, req: reqwest::blocking::RequestBuilder) -> reqwest::blocking::RequestBuilder {
        if let Some(ref key) = self.api_key {
            if self.api_format == "anthropic" {
                req.header("x-api-key", key)
                   .header("anthropic-version", "2023-06-01")
            } else {
                req.header("Authorization", format!("Bearer {}", key))
            }
        } else {
            req
        }
    }

    /// Extract tool calls from an OpenAI-format response.
    fn extract_tool_calls_openai(json: &serde_json::Value) -> Vec<ToolCall> {
        let mut calls = Vec::new();
        if let Some(tool_calls) = json["choices"][0]["message"]["tool_calls"].as_array() {
            for tc in tool_calls {
                let name = tc["function"]["name"].as_str().unwrap_or("").to_string();
                let id = tc["id"].as_str().unwrap_or("").to_string();
                let args_str = tc["function"]["arguments"].as_str().unwrap_or("{}");
                let arguments: std::collections::HashMap<String, serde_json::Value> =
                    serde_json::from_str(args_str).unwrap_or_default();
                calls.push(ToolCall { name, arguments, id });
            }
        }
        calls
    }

    /// Extract tool calls from an Anthropic-format response.
    fn extract_tool_calls_anthropic(json: &serde_json::Value) -> Vec<ToolCall> {
        let mut calls = Vec::new();
        if let Some(content) = json["content"].as_array() {
            for block in content {
                if block["type"].as_str() == Some("tool_use") {
                    let name = block["name"].as_str().unwrap_or("").to_string();
                    let id = block["id"].as_str().unwrap_or("").to_string();
                    let arguments: std::collections::HashMap<String, serde_json::Value> =
                        if let Some(input) = block["input"].as_object() {
                            input.iter().map(|(k, v)| (k.clone(), v.clone())).collect()
                        } else {
                            std::collections::HashMap::new()
                        };
                    calls.push(ToolCall { name, arguments, id });
                }
            }
        }
        calls
    }

    /// Parse response JSON into AgentResponse (format-aware).
    pub fn parse_response(&self, json: serde_json::Value) -> AgentResponse {
        if self.api_format == "anthropic" {
            let content = json["content"].as_array()
                .and_then(|arr| arr.iter()
                    .find(|b| b["type"].as_str() == Some("text"))
                    .and_then(|b| b["text"].as_str()))
                .unwrap_or("")
                .to_string();
            let input_tokens = json["usage"]["input_tokens"].as_u64().unwrap_or(0);
            let output_tokens = json["usage"]["output_tokens"].as_u64().unwrap_or(0);
            let tool_calls = Self::extract_tool_calls_anthropic(&json);
            AgentResponse {
                content, input_tokens, output_tokens,
                model: self.model.clone(),
                tool_calls,
            }
        } else {
            let content = json["choices"][0]["message"]["content"]
                .as_str().unwrap_or("").to_string();
            let input_tokens = json["usage"]["prompt_tokens"].as_u64().unwrap_or(0);
            let output_tokens = json["usage"]["completion_tokens"].as_u64().unwrap_or(0);
            let tool_calls = Self::extract_tool_calls_openai(&json);
            AgentResponse {
                content, input_tokens, output_tokens,
                model: self.model.clone(),
                tool_calls,
            }
        }
    }
}

impl AgentBackend for ApiBackend {
    fn send_message(&self, message: &str, context: &[Message]) -> AgentResponse {
        let client = reqwest::blocking::Client::new();
        let mut body = self.build_request_body(message, context);

        if self.stream {
            body["stream"] = serde_json::json!(true);
            // Request usage metadata in streaming responses
            if self.api_format == "openai" {
                body["stream_options"] = serde_json::json!({"include_usage": true});
            }
            let (content, input_tokens, output_tokens) = send_streaming(
                &client,
                &self.endpoint,
                self.api_key.as_deref(),
                &self.api_format,
                body,
            );
            return AgentResponse {
                content,
                input_tokens,
                output_tokens,
                model: self.model.clone(),
                ..Default::default()
            };
        }

        let req = client.post(&self.endpoint)
            .header("Content-Type", "application/json");
        let req = self.add_auth_header(req);

        match req.json(&body).send() {
            Ok(resp) => {
                match resp.json::<serde_json::Value>() {
                    Ok(json) => self.parse_response(json),
                    Err(e) => AgentResponse {
                        content: format!("JSON parse error: {}", e),
                        model: self.model.clone(),
                        ..Default::default()
                    },
                }
            }
            Err(e) => AgentResponse {
                content: format!("HTTP error: {}", e),
                model: self.model.clone(),
                ..Default::default()
            },
        }
    }

    fn name(&self) -> &str { &self.backend_name }
    fn supports_streaming(&self) -> bool { true }
}



/// Async interface for agent backends (tokio-based).
pub trait AsyncAgentBackend {
    /// Send a message asynchronously and return the response.
    fn send_message_async(&self, message: &str, context: &[Message])
        -> std::pin::Pin<Box<dyn std::future::Future<Output = AgentResponse> + Send + '_>>;

    /// Return the backend name.
    fn name(&self) -> &str;

    /// Whether this backend supports streaming.
    fn supports_streaming(&self) -> bool { false }
}

/// Async wrapper around ApiBackend for non-blocking HTTP calls.
pub struct AsyncApiBackend {
    pub inner: ApiBackend,
}

impl AsyncApiBackend {
    pub fn new(name: &str, endpoint: &str, api_key: Option<String>, model: &str, stream: bool, api_format: &str) -> Self {
        Self {
            inner: ApiBackend::new(name, endpoint, api_key, model, stream, api_format),
        }
    }

    fn add_auth_header(&self, req: reqwest::RequestBuilder) -> reqwest::RequestBuilder {
        if let Some(ref key) = self.inner.api_key {
            if self.inner.api_format == "anthropic" {
                req.header("x-api-key", key)
                   .header("anthropic-version", "2023-06-01")
            } else {
                req.header("Authorization", format!("Bearer {}", key))
            }
        } else {
            req
        }
    }

    /// Send a non-streaming async request. Returns Err for retryable failures.
    pub async fn send_async(&self, message: &str, context: &[Message]) -> Result<AgentResponse, String> {
        let client = reqwest::Client::new();
        let body = self.inner.build_request_body(message, context);

        let req = client.post(&self.inner.endpoint)
            .header("Content-Type", "application/json");
        let req = self.add_auth_header(req);

        match req.json(&body).send().await {
            Ok(resp) => {
                let status = resp.status().as_u16();
                if matches!(status, 408 | 429 | 500 | 502 | 503 | 504) {
                    return Err(format!("HTTP {} (retryable)", status));
                }
                match resp.json::<serde_json::Value>().await {
                    Ok(json) => Ok(self.inner.parse_response(json)),
                    Err(e) => Err(format!("JSON parse error: {}", e)),
                }
            }
            Err(e) => {
                if e.is_connect() || e.is_timeout() {
                    Err(format!("Connection error (retryable): {}", e))
                } else {
                    Ok(AgentResponse {
                        content: format!("HTTP error: {}", e),
                        model: self.inner.model.clone(),
                        ..Default::default()
                    })
                }
            }
        }
    }

    /// Send a streaming async request, calling on_token for each chunk.
    pub async fn send_streaming_async<F>(&self, message: &str, context: &[Message], mut on_token: F) -> AgentResponse
    where F: FnMut(&str)
    {
        use futures::StreamExt;
        let client = reqwest::Client::new();
        let mut body = self.inner.build_request_body(message, context);
        body["stream"] = serde_json::json!(true);
        if self.inner.api_format != "anthropic" {
            body["stream_options"] = serde_json::json!({"include_usage": true});
        }

        let req = client.post(&self.inner.endpoint)
            .header("Content-Type", "application/json");
        let req = self.add_auth_header(req);

        match req.json(&body).send().await {
            Ok(resp) => {
                let mut full_content = String::new();
                let mut input_tokens: u64 = 0;
                let mut output_tokens: u64 = 0;
                let mut stream = resp.bytes_stream();

                let mut buffer = String::new();
                while let Some(chunk) = stream.next().await {
                    match chunk {
                        Ok(bytes) => {
                            buffer.push_str(&String::from_utf8_lossy(&bytes));
                            while let Some(line_end) = buffer.find('\n') {
                                let line = buffer[..line_end].to_string();
                                buffer = buffer[line_end + 1..].to_string();
                                if let Some(data) = line.strip_prefix("data: ") {
                                    if data.trim() == "[DONE]" { continue; }
                                    if let Ok(json) = serde_json::from_str::<serde_json::Value>(data) {
                                        // Extract token from delta
                                        let token = if self.inner.api_format == "anthropic" {
                                            json["delta"]["text"].as_str().unwrap_or("").to_string()
                                        } else {
                                            json["choices"][0]["delta"]["content"].as_str().unwrap_or("").to_string()
                                        };
                                        if !token.is_empty() {
                                            on_token(&token);
                                            full_content.push_str(&token);
                                        }
                                        // Extract usage if present
                                        if let Some(usage) = json.get("usage") {
                                            if let Some(it) = usage["input_tokens"].as_u64()
                                                .or(usage["prompt_tokens"].as_u64()) {
                                                input_tokens = it;
                                            }
                                            if let Some(ot) = usage["output_tokens"].as_u64()
                                                .or(usage["completion_tokens"].as_u64()) {
                                                output_tokens = ot;
                                            }
                                        }
                                    }
                                }
                            }
                        }
                        Err(e) => {
                            if !full_content.is_empty() {
                                // Partial response recovered — notify but keep content
                                full_content.push_str(&format!("

[Stream interrupted: {}. Partial response above.]", e));
                            } else {
                                full_content = format!("[Stream error: {}]", e);
                            }
                            break;
                        }
                    }
                }

                AgentResponse {
                    content: full_content,
                    input_tokens,
                    output_tokens,
                    model: self.inner.model.clone(),
                    ..Default::default()
                }
            }
            Err(e) => AgentResponse {
                content: format!("HTTP error: {}", e),
                model: self.inner.model.clone(),
                ..Default::default()
            },
        }
    }
}

impl AsyncAgentBackend for AsyncApiBackend {
    fn send_message_async(&self, message: &str, context: &[Message])
        -> std::pin::Pin<Box<dyn std::future::Future<Output = AgentResponse> + Send + '_>>
    {
        let msg = message.to_string();
        let ctx = context.to_vec();
        Box::pin(async move {
            self.send_async(&msg, &ctx).await.unwrap_or_default()
        })
    }

    fn name(&self) -> &str { self.inner.name() }
    fn supports_streaming(&self) -> bool { true }
}

/// Create a backend from configuration.
pub fn create_backend(config: &AgentConfig) -> Box<dyn AgentBackend> {
    match config.backend.as_str() {
        "coro" => Box::new(CliBackend::new("coro", "claude", &[], config.model.clone())),
        "claude-code" => Box::new(CliBackend::new("claude-code", "claude", &["--print", "--model"], config.model.clone().or(Some("sonnet".to_string())))),
        "gemini" => {
            let m = config.model.clone().unwrap_or("gemini-2.5-flash".to_string());
            let validated = validate_gemini_model(&m, "gemini-2.5-flash");
            Box::new(CliBackend::new("gemini", "gemini", &["--model"], Some(validated)))
        }
        "claude" => {
            let key = std::env::var("ANTHROPIC_API_KEY").ok().or(config.api_key.clone());
            let model = config.model.clone().unwrap_or_default();
            Box::new(ApiBackend::new("claude", "https://api.anthropic.com/v1/messages", key, &model, config.stream, "anthropic"))
        }
        "openai" => {
            let key = std::env::var("OPENAI_API_KEY").ok().or(config.api_key.clone());
            let model = config.model.clone().unwrap_or_default();
            Box::new(ApiBackend::new("openai", "https://api.openai.com/v1/chat/completions", key, &model, config.stream, "openai"))
        }
        "openrouter" => {
            let key = std::env::var("OPENROUTER_API_KEY").ok().or(config.api_key.clone());
            let model = config.model.clone().unwrap_or_default();
            Box::new(ApiBackend::new("openrouter", "https://openrouter.ai/api/v1/chat/completions", key, &model, config.stream, "openai"))
        }
        "ollama-api" => Box::new(ApiBackend::new("ollama-api", "http://localhost:11434/api/chat", None, &config.model.clone().unwrap_or_default(), config.stream, "openai")),
        "ollama-cli" => Box::new(CliBackend::new("ollama-cli", "ollama", &[], config.model.clone().or(Some("llama3".to_string())))),
        _ => panic!("Unknown backend: {}", config.backend),
    }
}

